  "title": "फ़्लोटिंग पॉइंट्स की सटीकता",
  "group": "गणित",
  "options": [
    {
      "text": "0.1 + 0.2 === 0.3"
    },
    {
      "text": "false"
    },
    {
      "text": "true"
